var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"만세! 이겼다!","JPN":"わーい！　勝った！","ENG":"Yay! We won!","TWN":"萬歲！打贏咧！"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"하핫. 좋았어. 이걸로 며칠은 돈 걱정 없이 지내겠구만.","JPN":"ははっ。よし。これで数日は金の心配をしないで済むな。","ENG":"Ha ha! Nice. I'll be eatin' good for a couple of days now.","TWN":"哈哈，非常好，這樣接下來幾天的花費就有著落了。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이 침식 쐐기는 혹시 몇 종인가요? 3종이죠? 네?","JPN":"この侵食楔は何種ですか？　第3種ですよね？　ね？","ENG":"What category is this Corrupted Wedge? It's a Category 3, right?","TWN":"這個侵蝕釘是幾類啊？是3類吧？是吧？"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"뭐야, 저 녀석은. 3종이라니 재수 없게.","JPN":"なんだ、あいつは。第3種だなんて、縁起悪い。","ENG":"Ugh, this again? You just won't let it go, will you?","TWN":"你這小丫頭，什麼3類，觸霉頭！"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"PMC_NPC_COMPLETE_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"신경 꺼. 애가 순진한데 좀 얼빵하더라.","JPN":"気にするな。純粋だけどちょっとずれてるんだ。","ENG":"Leave her be. She's a good kid, just a little stupid in the head.","TWN":"別管她，她還很單純，有點呆呆的。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"PMC_NPC_COMPLETE_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"노엘이라고 했지?","JPN":"ノエルだっけか？","ENG":"Noelle, right?","TWN":"你叫洛艾兒對吧？"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"나도 경력이 긴 편은 아니지만 조언 하나 해 줄게. 그 회사에 들어가는 건 그만둬.","JPN":"俺も経歴がそう長い方ではないが、一つアドバイスしてやろう。あの会社に入るのはやめておけ。","ENG":"Though I'm not that experienced, let me give you some advice. Give up trying to get into that company.","TWN":"雖然我的資歷不算久，但我給你個建議，我勸你打消進去那家公司的念頭。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그치만 지금이 아니면 언제 또 채용을 할지 모르는 걸요.","JPN":"でも、今じゃないとまたいつ採用があるかわからないんです。","ENG":"But if I miss my chance now, there's no telling when they're gonna hire again.","TWN":"可是錯過這次機會的話，下次不知道時候才會再徵人。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저는 이번 기회를 잡기로 결심했어요!","JPN":"私はこのチャンスに賭けてるんです！","ENG":"That's why I decided to seize this opportunity!","TWN":"我已經決定要抓住這次的機會！"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"야. 내가 살면서 3종 침식체 잡는 게 입사 기준인 회사는 한 번도 못 들어봤다.","JPN":"おい。第3種侵食体を捕まえんのが入社条件だって会社、今まで聞いたことがねえぞ。","ENG":"Hey, I've never heard of a company having to defeat a Category 3 C.O. as a requirement for joining.","TWN":"喂，我活到現在，還沒聽過哪間公司要求抓到3類侵蝕體才錄取的。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"뭐? 그런 미친 데는 관리국에 신고해야지!","JPN":"は？　そんな会社は管理局に通報もんだぜ！","ENG":"What? We should report that to the Administration! That's crazy!","TWN":"什麼？要跟管理局投訴這種無良公司吧！"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_COMPLETE_A","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"보아하니 초짜 같은데, 첫 직장은 신중하게 골라야 하는 거야.","JPN":"新人のようだが、最初の職場は慎重に選ぶべきだ。","ENG":"You seem to be new to all of this, but you gotta be careful when choosing your first company.","TWN":"我看你應該是職場新鮮人吧？第一間公司一定要慎選。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"나도 영 상태 안 좋은 데 들어갔다가 지금 이렇게 프리랜서 신세라고.","JPN":"俺もボロいところに入っちまったから、今はこうやってフリーの傭兵をやってるんだ。","ENG":"I joined one that wasn't in good shape, and look at me now. I'm a freelancer doing odd jobs.","TWN":"我就是進錯公司，現在才會淪為自由工作者。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우으…. 전 용병이 아니라 펜릴 소대원이 되고 싶은 건데.","JPN":"うう……私は傭兵じゃなくてフェンリル小隊員になりたいのに。","ENG":"Err... But I want to be a Fenrir Squad member, not a mercenary.","TWN":"呃，可是…我不是想當傭兵，我是想當芬里爾小隊員。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"거 너희들 그러지 말고 그냥 우리랑 같이 일하지 그래?","JPN":"お前ら、それより俺らと一緒に働くのはどうだ？","ENG":"Yo, you two. How about just working with us?","TWN":"你們別再爭啦。我說，哥乾脆和我們一起做事吧？"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_COMPLETE_A","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"그래. 쟤는 몰라도 형씨는 한 실력 하더만.","JPN":"そうだ。あいつは知らんけど、あんたは結構腕が立つだろ？","ENG":"Yeah, I'm not sure about her, but you're one tough fighter.","TWN":"對啊，她實力如何我是不清楚，但哥的實力真的有兩下子喔。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_COMPLETE_A","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"낄낄. 전설이 된 태스크포스들은 다들 현장에서 우연히 만났다고들 하지.","JPN":"ククッ。伝説のタスクフォースはみんな現場で偶然出会ったってな。","ENG":"Keke. Legendary TASKFORCEs all claim to have met each other out on the field by chance.","TWN":"嘿嘿，我聽說傳說中的特遣勢力都是從現場巧遇開始的。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_COMPLETE_A","face":"UNIT_IDLE"}}}}]`);export{e as default};